{
  "summary": "This paper proposes a method to create noisy parallel corpora for code translation by leveraging document similarity metrics, enabling supervised training of code translation models without requiring expensive parallel data. Through extensive experiments on multiple datasets and languages, the authors demonstrate that models trained on these noisy datasets maintain strong performance and that the approach scales to a wide range of programming languages.",
  "strengths": [
    {
      "point": "Novel approach to creating noisy parallel datasets using document similarity.",
      "evidence": "The paper introduces a method leveraging similarity metrics such as Word Movers Distance to pair code samples across languages, enabling parallel corpus creation without manual annotation."
    },
    {
      "point": "Empirical demonstration of noise tolerance in code translation models.",
      "evidence": "Experiments show that models trained on noisy datasets with up to ~30% noise degrade performance only gradually, with about 1% BLEU drop at ~90% match accuracy."
    },
    {
      "point": "Scalability to multiple programming languages and practical utility.",
      "evidence": "The method is applied to 10 languages in the CodeNet dataset, showing improved computational accuracy over random baselines and enabling translation for less-explored language pairs."
    },
    {
      "point": "Validation using state-of-the-art pre-trained models.",
      "evidence": "Fine-tuning CodeBERT, GraphCodeBERT, and PLBART on the created datasets demonstrates improved translation accuracy compared to baselines."
    },
    {
      "point": "Provision of resources to support reproducibility.",
      "evidence": "The authors provide source code and dataset subsets to facilitate further research."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to recent unsupervised or weakly supervised code translation methods.",
      "evidence": "The paper lacks direct empirical comparisons or discussions on how the noisy parallel data approach quantitatively outperforms or complements prior unsupervised methods."
    },
    {
      "point": "Lack of principled justification or ablation for similarity threshold selection.",
      "evidence": "No ablation study or sensitivity analysis is provided for the similarity threshold δ used in pairing documents."
    },
    {
      "point": "No exploration of alternative pairing strategies such as one-to-many matching.",
      "evidence": "The method restricts to one-to-one pairing without justification or ablation on this design choice."
    },
    {
      "point": "Weak baselines in evaluation beyond random pairing.",
      "evidence": "The main baseline is random pairing; stronger heuristic or semi-supervised baselines like keyword or function signature matching are not considered."
    },
    {
      "point": "Evaluation metrics focus on surface similarity without semantic or execution-based validation.",
      "evidence": "Metrics used are BLEU, CodeBLEU, and Exact Match; semantic correctness or functional equivalence metrics such as test case pass rates are not deeply analyzed."
    },
    {
      "point": "Limited analysis of noise types and their impact on model performance.",
      "evidence": "The paper does not characterize the types of noise present in the noisy datasets, limiting interpretability of robustness results."
    },
    {
      "point": "Insufficient details for reproducibility regarding preprocessing and hyperparameters.",
      "evidence": "Details on code tokenization, handling of comments, formatting, and hyperparameters for similarity methods like LDA and WMD are missing."
    },
    {
      "point": "Ambiguity in definitions and metrics reduces clarity.",
      "evidence": "The term 'document' is not clearly defined, and the pseudo-match accuracy metric lacks detailed explanation."
    },
    {
      "point": "No discussion of language-specific challenges or structural differences.",
      "evidence": "The approach treats code as text and does not address how language features or structural differences affect pairing quality or translation."
    },
    {
      "point": "Limited generalizability beyond competitive programming datasets.",
      "evidence": "Experiments are restricted to CodeNet and do not evaluate on real-world legacy code migration tasks or less popular languages."
    },
    {
      "point": "No statistical significance testing reported.",
      "evidence": "Reported metric differences lack confidence intervals or significance tests, leaving robustness uncertain."
    }
  ],
  "questions": [
    {
      "question": "How does the noisy parallel data approach compare quantitatively to recent unsupervised or weakly supervised code translation methods?",
      "motivation": "Understanding relative performance is critical to assess the practical advantage of the proposed method."
    },
    {
      "question": "How sensitive are results to the similarity threshold δ and the one-to-one pairing constraint?",
      "motivation": "These design choices impact dataset quality and size, influencing model performance and generalizability."
    },
    {
      "question": "Can the method be effectively applied to real-world legacy codebases beyond competitive programming datasets?",
      "motivation": "Demonstrating utility on practical legacy migration tasks would strengthen the method's applicability claims."
    },
    {
      "question": "What types of noise dominate the noisy parallel datasets, and how do they affect model robustness?",
      "motivation": "Characterizing noise can guide improvements in dataset creation and model training strategies."
    },
    {
      "question": "Would incorporating semantic or execution-based evaluation metrics alter conclusions about model performance on noisy data?",
      "motivation": "Surface-level metrics may not fully capture translation correctness, so deeper evaluation is important."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
